CREATE TRIGGER [dbo].[WorkElementTypeAttribute_History]ON [dbo].[WorkElementTypeAttribute]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.WorkElementTypeAttributeId IS NOT NULL AND d.WorkElementTypeAttributeId IS NULL THEN 'I' 		WHEN i.WorkElementTypeAttributeId IS NOT NULL AND d.WorkElementTypeAttributeId IS NOT NULL THEN 'U' 		WHEN i.WorkElementTypeAttributeId IS NULL AND d.WorkElementTypeAttributeId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.WorkElementTypeAttributeId = d.WorkElementTypeAttributeId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_WorkElementTypeAttribute([WorkElementTypeAttributeId], [WorkElementTypeId], [Name], [IsRequiredAtSetup], [IsRequiredAtRun], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [WorkElementTypeAttributeId], [WorkElementTypeId], [Name], [IsRequiredAtSetup], [IsRequiredAtRun], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_WorkElementTypeAttribute([WorkElementTypeAttributeId], [WorkElementTypeId], [Name], [IsRequiredAtSetup], [IsRequiredAtRun], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [WorkElementTypeAttributeId], [WorkElementTypeId], [Name], [IsRequiredAtSetup], [IsRequiredAtRun], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND